CREATE SCHEMA IF NOT EXISTS cad;

CREATE OR REPLACE FUNCTION cad.add_shape(p_drawing_id integer, p_layer_id integer, p_type text, p_geometry jsonb, p_props jsonb DEFAULT '{}'::jsonb, p_label text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_order int;
BEGIN
  SELECT COALESCE(max(sort_order), 0) + 1 INTO v_order
  FROM cad.shape WHERE drawing_id = p_drawing_id;

  INSERT INTO cad.shape (drawing_id, layer_id, type, geometry, props, label, sort_order)
  VALUES (p_drawing_id, p_layer_id, p_type, p_geometry, p_props, p_label, v_order)
  RETURNING id INTO v_id;

  UPDATE cad.drawing SET updated_at = now() WHERE id = p_drawing_id;

  RETURN v_id;
END;
$function$;

CREATE OR REPLACE FUNCTION cad.bill_of_materials(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text;
  v_drawing cad.drawing;
BEGIN
  SELECT * INTO v_drawing FROM cad.drawing WHERE id = p_drawing_id;
  IF NOT FOUND THEN RETURN 'Dessin non trouvé'; END IF;

  SELECT string_agg(line, E'\n' ORDER BY role, sid) INTO v_rows
  FROM (
    SELECT
      s.id AS sid,
      COALESCE(s.props->>'role', '') AS role,
      format('| %s | %s | %s | %s | %s %s |',
        COALESCE(s.label, '#' || s.id),
        COALESCE(s.props->>'role', '-'),
        COALESCE(s.props->>'wood_type', '-'),
        COALESCE(s.props->>'section', '-'),
        CASE s.type
          WHEN 'line' THEN round(sqrt(
            ((s.geometry->>'x2')::real - (s.geometry->>'x1')::real)^2 +
            ((s.geometry->>'y2')::real - (s.geometry->>'y1')::real)^2
          )::numeric, 0)::text
          WHEN 'rect' THEN round(greatest(
            (s.geometry->>'w')::numeric,
            (s.geometry->>'h')::numeric
          ), 0)::text
          ELSE '?'
        END,
        v_drawing.unit
      ) AS line
    FROM cad.shape s
    WHERE s.drawing_id = p_drawing_id
      AND s.props ? 'section'
  ) sub;

  IF v_rows IS NULL THEN
    RETURN '<p>Aucune pièce bois dans ce dessin.</p>';
  END IF;

  RETURN '<md>' || E'\n'
    || '| Pièce | Rôle | Essence | Section | Longueur |' || E'\n'
    || '|-------|------|---------|---------|----------|' || E'\n'
    || v_rows || E'\n'
    || '</md>';
END;
$function$;

CREATE OR REPLACE FUNCTION cad.delete_shape(p_shape_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing_id int;
BEGIN
  DELETE FROM cad.shape WHERE id = p_shape_id RETURNING drawing_id INTO v_drawing_id;
  IF v_drawing_id IS NOT NULL THEN
    UPDATE cad.drawing SET updated_at = now() WHERE id = v_drawing_id;
  END IF;
END;
$function$;

CREATE OR REPLACE FUNCTION cad.drawing_add(name text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  IF name IS NULL OR trim(name) = '' THEN
    RETURN '<template data-toast="error">Nom requis</template>';
  END IF;

  INSERT INTO cad.drawing (name) VALUES (trim(name)) RETURNING id INTO v_id;

  -- Créer un calque par défaut
  INSERT INTO cad.layer (drawing_id, name, color, stroke_width)
  VALUES (v_id, 'Structure', '#333333', 1.5);

  RETURN format('<template data-redirect="/drawing/%s"></template>', v_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.move_shape(p_shape_id integer, p_dx real, p_dy real)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_shape cad.shape;
  v_g jsonb;
  v_pts jsonb;
BEGIN
  SELECT * INTO v_shape FROM cad.shape WHERE id = p_shape_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'shape % not found', p_shape_id; END IF;

  v_g := v_shape.geometry;

  CASE v_shape.type
    WHEN 'line', 'dimension' THEN
      v_g := jsonb_set(v_g, '{x1}', to_jsonb((v_g->>'x1')::real + p_dx));
      v_g := jsonb_set(v_g, '{y1}', to_jsonb((v_g->>'y1')::real + p_dy));
      v_g := jsonb_set(v_g, '{x2}', to_jsonb((v_g->>'x2')::real + p_dx));
      v_g := jsonb_set(v_g, '{y2}', to_jsonb((v_g->>'y2')::real + p_dy));

    WHEN 'rect' THEN
      v_g := jsonb_set(v_g, '{x}', to_jsonb((v_g->>'x')::real + p_dx));
      v_g := jsonb_set(v_g, '{y}', to_jsonb((v_g->>'y')::real + p_dy));

    WHEN 'circle', 'arc' THEN
      v_g := jsonb_set(v_g, '{cx}', to_jsonb((v_g->>'cx')::real + p_dx));
      v_g := jsonb_set(v_g, '{cy}', to_jsonb((v_g->>'cy')::real + p_dy));

    WHEN 'text' THEN
      v_g := jsonb_set(v_g, '{x}', to_jsonb((v_g->>'x')::real + p_dx));
      v_g := jsonb_set(v_g, '{y}', to_jsonb((v_g->>'y')::real + p_dy));

    WHEN 'polyline' THEN
      SELECT jsonb_agg(jsonb_build_array(
        (p->0)::real + p_dx,
        (p->1)::real + p_dy
      )) INTO v_pts
      FROM jsonb_array_elements(v_g->'points') AS p;
      v_g := jsonb_set(v_g, '{points}', v_pts);

    ELSE NULL;
  END CASE;

  UPDATE cad.shape SET geometry = v_g WHERE id = p_shape_id;
  UPDATE cad.drawing SET updated_at = now() WHERE id = v_shape.drawing_id;
END;
$function$;

